from __future__ import annotations

"""
raw_questions.py
Single source of truth for all 500 seed questions.
Sourced from:
- DSA: 100 questions (ids 1–100)
- CN: 100 questions (ids 1–100)
- OS: 100 questions (ids 1–100)
- DBMS: 100 questions (ids 1–100)
- System Design: 100 questions (ids 1–100)
"""

RAW: list[dict] = []

# ══════════════════════════════════════════════════════════════════════════════
# HELPERS
# ══════════════════════════════════════════════════════════════════════════════

def add_dsa(id, topic, difficulty, question, approaches):
    """Adds DSA questions with approach splitting."""
    for app in approaches:
        slug = app["approach_name"].lower().replace(" ", "_").replace("-", "_").replace("(", "").replace(")", "")
        RAW.append({
            "question_id": f"DSA_{id}_{slug}",
            "subject": "DSA",
            "difficulty": difficulty,
            "topic": topic,
            "approach_label": app["approach_name"],
            "question_text": question,
            "approach_summary": app["description"],
            "is_optimal": app["is_optimal"],
            "tags": [topic, difficulty, "DSA"],
            "rubric": {}
        })

def add_theory_subject(id, subject, topic, difficulty, question, approaches):
    """Adds Theory questions (CN, OS, DBMS, SD) with approach splitting and 0-3 point rubric."""
    for app in approaches:
      print(app['approach_name'])
      slug = app['approach_name'].lower().replace(" ", "_").replace("-", "_").replace("(", "").replace(")", "").replace("/", "_")
      RAW.append({
            "question_id": f"{subject}_{id}_{slug}",
            "subject": subject,
            "difficulty": difficulty,
            "topic": topic,
            "approach_label": app["approach_name"],
            "question_text": question,
            "approach_summary": app["description"],
            "is_optimal": app["is_optimal"],
            "tags": [topic, difficulty, subject],
            "rubric": {
                "0": "Incorrect or irrelevant. Shows fundamental misunderstanding of the concept.",
                "1": "Identifies some key terms but lacks a cohesive explanation of the mechanism.",
                "2": "Technically accurate but incomplete; missing critical details regarding overhead or performance.",
                "3": "Comprehensive technical explanation of the optimal solution, addressing constraints and trade-offs."
            }
        })

